{% extends "dashboard/base_dashboard.html" %}
{% load static %}

{% block title %}{% if category %}Edit{% else %}Add{% endif %} Category — Dashboard{% endblock %}
{% block page_title %}{% if category %}Edit Category{% else %}Add Category{% endif %}{% endblock %}
{% block nav_categories %}active{% endblock %}

{% block extra_styles %}
.form-card { background: var(--surface); border: 1px solid var(--border); border-radius: var(--r-lg); padding: 28px; max-width: 600px; }
.form-group { margin-bottom: 20px; }
.form-label { display: block; font-size: 12px; font-weight: 600; color: var(--text-sub); text-transform: uppercase; letter-spacing: .06em; margin-bottom: 6px; }
.form-input, .form-select, .form-textarea {
  width: 100%; height: 40px; border: 1.5px solid var(--border); border-radius: var(--r);
  padding: 0 12px; font-family: 'DM Sans', sans-serif; font-size: 13px; color: var(--text);
  background: var(--surface); outline: none; transition: border-color .15s;
}
.form-input:focus, .form-select:focus, .form-textarea:focus { border-color: var(--navy); }
.form-textarea { height: 90px; padding: 10px 12px; resize: vertical; }
.form-hint { font-size: 11px; color: var(--text-muted); margin-top: 4px; }
.btn { display: inline-flex; align-items: center; gap: 6px; padding: 0 18px; height: 38px; border-radius: var(--r); font-family: 'DM Sans', sans-serif; font-size: 13px; font-weight: 500; cursor: pointer; border: none; text-decoration: none; transition: all .15s; }
.btn-navy { background: var(--navy); color: #fff; }
.btn-navy:hover { background: var(--navy-hover); }
.btn-ghost { background: transparent; color: var(--text-sub); border: 1.5px solid var(--border); }
.btn-ghost:hover { border-color: var(--navy); color: var(--navy); }
.img-preview { width: 80px; height: 80px; border-radius: var(--r); border: 1.5px solid var(--border); object-fit: cover; margin-bottom: 8px; display: block; }
{% endblock %}

{% block dashboard_content %}
<div style="margin-bottom:16px;">
  <a href="/dashboard/categories/" style="font-size:13px;color:var(--text-muted);text-decoration:none;">← Back to Categories</a>
</div>

<div class="form-card">
  <form method="post" enctype="multipart/form-data">
    {% csrf_token %}

    <div class="form-group">
      <label class="form-label">Name *</label>
      <input class="form-input" type="text" name="name" value="{{ category.name|default:'' }}" required
             placeholder="e.g. Phones" id="id_name">
    </div>

    <div class="form-group">
      <label class="form-label">Slug</label>
      <input class="form-input" type="text" name="slug" value="{{ category.slug|default:'' }}"
             placeholder="auto-generated from name" id="id_slug">
      <div class="form-hint">Leave blank to auto-generate. Used in URLs.</div>
    </div>

    <div class="form-group">
      <label class="form-label">Description</label>
      <textarea class="form-textarea" name="description" placeholder="Optional description…">{{ category.description|default:'' }}</textarea>
    </div>

    <div class="form-group">
      <label class="form-label">Parent Category</label>
      <select class="form-select" name="parent">
        <option value="">— None (top-level) —</option>
        {% for p in parents %}
          <option value="{{ p.pk }}" {% if category.parent_id == p.pk %}selected{% endif %}>{{ p.name }}</option>
        {% endfor %}
      </select>
    </div>

    <div class="form-group">
      <label class="form-label">Display Order</label>
      <input class="form-input" type="number" name="order" value="{{ category.order|default:0 }}" min="0" style="max-width:120px;">
      <div class="form-hint">Lower numbers appear first.</div>
    </div>

    <div class="form-group">
      <label class="form-label">Icon (Emoji)</label>
      <input class="form-input" type="text" name="icon" value="{{ category.icon|default:'' }}"
             placeholder="e.g. device-mobile or 📱" maxlength="10" style="max-width:160px;">
      <div class="form-hint">Paste an emoji to show as the category icon on the storefront.</div>
    </div>

    <div class="form-group">
      <label class="form-label">Image</label>
      {% if category.image %}
        <img src="{{ category.image.url }}" alt="{{ category.name }}" class="img-preview">
      {% endif %}
      <input type="file" name="image" accept="image/*" style="font-size:13px;">
    </div>

    <div style="display:flex;gap:10px;margin-top:8px;">
      <button type="submit" class="btn btn-navy">{% if category %}Save Changes{% else %}Create Category{% endif %}</button>
      <a href="/dashboard/categories/" class="btn btn-ghost">Cancel</a>
    </div>
  </form>
</div>

<script>
// Auto-generate slug from name
const nameInput = document.getElementById('id_name');
const slugInput = document.getElementById('id_slug');
let slugEdited = slugInput.value.length > 0;
slugInput.addEventListener('input', () => { slugEdited = true; });
nameInput.addEventListener('input', () => {
  if (slugEdited) return;
  slugInput.value = nameInput.value.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
});
</script>
{% endblock %}

{% extends "dashboard/base_dashboard.html" %}
{% load humanize icon_tags %}

{% block title %}Categories — Dashboard{% endblock %}
{% block page_title %}Categories{% endblock %}
{% block nav_categories %}active{% endblock %}

{% block extra_styles %}
.table-wrap { background: var(--surface); border: 1px solid var(--border); border-radius: var(--r-lg); overflow: hidden; }
table { width: 100%; border-collapse: collapse; }
thead th { padding: 11px 16px; text-align: left; font-size: 11px; font-weight: 600; color: var(--text-muted); text-transform: uppercase; letter-spacing: .06em; background: var(--surface-alt); border-bottom: 1px solid var(--border); }
tbody tr { border-bottom: 1px solid var(--border); transition: background .12s; }
tbody tr:last-child { border-bottom: none; }
tbody tr:hover { background: var(--surface-alt); }
td { padding: 12px 16px; font-size: 13px; color: var(--text); vertical-align: middle; }
.td-img { width: 40px; height: 40px; border-radius: 8px; background: var(--surface-alt); border: 1px solid var(--border); overflow: hidden; display: flex; align-items: center; justify-content: center; font-size: 20px; flex-shrink: 0; }
.td-img img { width: 100%; height: 100%; object-fit: cover; }
.td-name { font-weight: 600; color: var(--navy); }
.btn { display: inline-flex; align-items: center; gap: 6px; padding: 0 14px; height: 34px; border-radius: var(--r); font-family: 'DM Sans', sans-serif; font-size: 13px; font-weight: 500; cursor: pointer; border: none; text-decoration: none; transition: all .15s; }
.btn-navy { background: var(--navy); color: #fff; }
.btn-navy:hover { background: var(--navy-hover); }
.btn-ghost { background: transparent; color: var(--text-sub); border: 1.5px solid var(--border); }
.btn-ghost:hover { border-color: var(--navy); color: var(--navy); }
.btn-danger { background: var(--danger-light); color: var(--danger); }
.btn-danger:hover { background: var(--danger); color: #fff; }
.empty-state { text-align: center; padding: 60px 20px; color: var(--text-muted); }
.empty-state .icon { font-size: 40px; margin-bottom: 12px; }
.empty-state p { font-size: 14px; }
{% endblock %}

{% block dashboard_content %}
<div class="page-header">
  <div>
    <div class="page-title serif">Categories</div>
    <div style="font-size:13px;color:var(--text-muted);margin-top:3px;">{{ categories|length }} categor{{ categories|length|pluralize:"y,ies" }}</div>
  </div>
  <a href="/dashboard/categories/add/" class="btn btn-navy">+ Add Category</a>
</div>

<div class="table-wrap">
  <table>
    <thead>
      <tr>
        <th>Image</th>
        <th>Name</th>
        <th>Slug</th>
        <th>Parent</th>
        <th>Products</th>
        <th>Order</th>
        <th>Actions</th>
      </tr>
    </thead>
    <tbody>
      {% for cat in categories %}
      <tr>
        <td>
          <div class="td-img">
            {% if cat.image %}<img src="{{ cat.image.url }}" alt="{{ cat.name }}">{% else %}{% icon "rows" size=24 color="var(--text-muted)" %}{% endif %}
          </div>
        </td>
        <td><div class="td-name">{{ cat.name }}</div></td>
        <td style="color:var(--text-muted);font-size:12px;">{{ cat.slug }}</td>
        <td style="color:var(--text-muted);">{{ cat.parent.name|default:"—" }}</td>
        <td style="font-weight:600;">{{ cat.product_count }}</td>
        <td style="color:var(--text-muted);">{{ cat.order }}</td>
        <td>
          <div style="display:flex;gap:6px;">
            <a href="/dashboard/categories/{{ cat.pk }}/edit/" class="btn btn-ghost">Edit</a>
            <form method="post" action="/dashboard/categories/{{ cat.pk }}/delete/" onsubmit="return confirm('Delete {{ cat.name }}?')">
              {% csrf_token %}
              <button type="submit" class="btn btn-danger">Delete</button>
            </form>
          </div>
        </td>
      </tr>
      {% empty %}
      <tr>
        <td colspan="7">
          <div class="empty-state">
            <div class="icon">{% icon "rows" size=48 color="var(--text-muted)" %}</div>
            <p>No categories yet. <a href="/dashboard/categories/add/" style="color:var(--navy);font-weight:600;">Add one</a>.</p>
          </div>
        </td>
      </tr>
      {% endfor %}
    </tbody>
  </table>
</div>
{% endblock %}

